  1→import { motion, AnimatePresence } from 'framer-motion';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useInfiniteQuery } from '@tanstack/react-query';
  4→import { getPromptResponses } from '../../../API/Api';
  5→import { MoonLoader } from 'react-spinners';
  6→import VerifiedBadge from '../Badge/VerifiedBadge';
  7→
  8→function timeAgo(dateStr) {
  9→    const seconds = Math.floor((Date.now() - new Date(dateStr).getTime()) / 1000);
 10→    if (seconds < 60) return 'just now';
 11→    const minutes = Math.floor(seconds / 60);
 12→    if (minutes < 60) return `${minutes}m ago`;
 13→    const hours = Math.floor(minutes / 60);
 14→    if (hours < 24) return `${hours}h ago`;
 15→    const days = Math.floor(hours / 24);
 16→    if (days < 30) return `${days}d ago`;
 17→    return new Date(dateStr).toLocaleDateString();
 18→}
 19→
 20→const PromptResponsesModal = ({ promptId, count, promptText, onClose }) => {
 21→    const navigate = useNavigate();
 22→
 23→    const {
 24→        data,
 25→        hasNextPage,
 26→        fetchNextPage,
 27→        isFetchingNextPage,
 28→    } = useInfiniteQuery({
 29→        queryKey: ['promptResponsesModal', promptId],
 30→        queryFn: ({ pageParam = null }) => getPromptResponses(promptId, pageParam, 5),
 31→        getNextPageParam: (lastPage) => {
 32→            if (lastPage?.hasMore) {
 33→                const last = lastPage.responses[lastPage.responses.length - 1];
 34→                return new Date(last.created_at).toISOString();
 35→            }
 36→            return undefined;
 37→        },
 38→        enabled: !!promptId,
 39→        refetchOnWindowFocus: false,
 40→        staleTime: 1000 * 60 * 5,
 41→    });
 42→
 43→    const responses = data?.pages?.flatMap(p => p.responses) || [];
 44→
 45→    const handleCardClick = (id) => {
 46→        onClose();
 47→        navigate(`/home/post/${id}`);
 48→    };
 49→
 50→    return (
 51→        <AnimatePresence>
 52→            <motion.div
 53→                className="prompt-responses-overlay"
 54→                initial={{ opacity: 0 }}
 55→                animate={{ opacity: 1 }}
 56→                exit={{ opacity: 0 }}
 57→                transition={{ duration: 0.2 }}
 58→                onClick={onClose}
 59→            >
 60→                <motion.div
 61→                    className="prompt-responses-modal"
 62→                    initial={{ opacity: 0, scale: 0.92, y: 20 }}
 63→                    animate={{ opacity: 1, scale: 1, y: 0 }}
 64→                    exit={{ opacity: 0, scale: 0.92, y: 20 }}
 65→                    transition={{ type: 'spring', stiffness: 400, damping: 30 }}
 66→                    onClick={(e) => e.stopPropagation()}
 67→                >
 68→                    <div className="prompt-responses-header">
 69→                        <div className="prompt-responses-header-text">
 70→                            <h3 className="prompt-responses-title">
 71→                                {count} {count === 1 ? 'Response' : 'Responses'}
 72→                            </h3>
 73→                            {promptText && (
 74→                                <p className="prompt-responses-prompt">
 75→                                    {promptText.length > 80 ? promptText.substring(0, 80) + '…' : promptText}
 76→                                </p>
 77→                            )}
 78→                        </div>
 79→                        <button className="prompt-responses-close" onClick={onClose}>
 80→                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
 81→                                <path d="M18.3 5.71a1 1 0 0 0-1.42 0L12 10.59 7.12 5.71a1 1 0 1 0-1.42 1.42L10.59 12l-4.88 4.88a1 1 0 1 0 1.42 1.42L12 13.41l4.88 4.88a1 1 0 0 0 1.42-1.42L13.41 12l4.88-4.88a1 1 0 0 0 0-1.41Z"/>
 82→                            </svg>
 83→                        </button>
 84→                    </div>
 85→
 86→                    <div className="prompt-responses-list">
 87→                        {responses.map((r) => (
 88→                            <div
 89→                                key={r.id}
 90→                                className="prompt-response-card"
 91→                                onClick={() => handleCardClick(r.id)}
 92→                            >
 93→                                <div className="prompt-response-author">
 94→                                    <div className={`prompt-response-avatar-wrap${r.users?.badge === 'legend' ? ' pr-ring-legend' : r.users?.badge === 'og' ? ' pr-ring-og' : ''}`}>
 95→                                        <img
 96→                                            src={r.users?.image_url || '/assets/profile.jpg'}
 97→                                            alt=""
 98→                                            className="prompt-response-avatar"
 99→                                        />
100→                                    </div>
101→                                    <span className="prompt-response-name">{r.users?.name || 'Anonymous'}</span>
102→                                    {r.users?.badge && <VerifiedBadge badge={r.users.badge} size={12} />}
103→                                </div>
104→                                <p className="prompt-response-title">{r.title}</p>
105→                                <span className="prompt-response-time">{timeAgo(r.created_at)}</span>
106→                            </div>
107→                        ))}
108→
109→                        {hasNextPage && (
110→                            <button
111→                                className="prompt-responses-see-more"
112→                                onClick={() => fetchNextPage()}
113→                                disabled={isFetchingNextPage}
114→                            >
115→                                {isFetchingNextPage ? (
116→                                    <MoonLoader size={14} color="var(--text-secondary, #a1a1aa)" />
117→                                ) : (
118→                                    'See more'
119→                                )}
120→                            </button>
121→                        )}
122→                    </div>
123→                </motion.div>
124→            </motion.div>
125→        </AnimatePresence>
126→    );
127→};
128→
129→export default PromptResponsesModal;
