 1→import React from 'react';
 2→import { motion } from 'framer-motion';
 3→import useAnimatedCounter from '../DashboardBriefing/useAnimatedCounter';
 4→
 5→const fmt = (n) => {
 6→    if (!n || n === 0) return '0';
 7→    if (n >= 1000000) return `${(n / 1000000).toFixed(1)}M`;
 8→    if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
 9→    return String(n);
10→};
11→
12→const Tile = ({ icon, value, label, index }) => {
13→    const animated = useAnimatedCounter(value, 900 + index * 50);
14→
15→    return (
16→        <motion.div
17→            className="analytics-stat-tile"
18→            initial={{ opacity: 0, y: 14 }}
19→            animate={{ opacity: 1, y: 0 }}
20→            transition={{ duration: 0.35, delay: 0.1 + index * 0.08, ease: 'easeOut' }}
21→        >
22→            <span className="analytics-tile-icon">{icon}</span>
23→            <span className="analytics-tile-value">{fmt(animated)}</span>
24→            <span className="analytics-tile-label">{label}</span>
25→        </motion.div>
26→    );
27→};
28→
29→const AnalyticsSummary = ({ summary }) => {
30→    if (!summary) return null;
31→
32→    const tiles = [
33→        { icon: '📝', value: summary.total_posts, label: 'posts' },
34→        { icon: '👁', value: summary.total_views, label: 'views' },
35→        { icon: '✨', value: summary.total_reactions, label: 'reactions' },
36→        { icon: '💬', value: summary.total_comments, label: 'comments' },
37→    ];
38→
39→    return (
40→        <div className="analytics-summary-grid">
41→            {tiles.map((t, i) => (
42→                <Tile key={t.label} icon={t.icon} value={t.value} label={t.label} index={i} />
43→            ))}
44→        </div>
45→    );
46→};
47→
48→export default AnalyticsSummary;
